-- SQL schema for Bitcoin Wallet System\n\nCREATE TABLE adr_users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(50) NOT NULL UNIQUE,\n    email VARCHAR(100) NOT NULL UNIQUE,\n    password_hash VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,\n    last_login TIMESTAMP\n);\n\nCREATE TABLE adr_wallets (\n    wallet_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES adr_users(user_id),\n    wallet_name VARCHAR(100) NOT NULL,\n    balance DECIMAL(20, 8) NOT NULL DEFAULT 0.0,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\nCREATE TABLE adr_transactions (\n    transaction_id SERIAL PRIMARY KEY,\n    sender_id INT REFERENCES adr_users(user_id),\n    receiver_id INT REFERENCES adr_users(user_id),\n    wallet_id INT REFERENCES adr_wallets(wallet_id),\n    amount DECIMAL(20, 8) NOT NULL,\n    transaction_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    status VARCHAR(20) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\nCREATE TABLE adr_settings (\n    setting_id SERIAL PRIMARY KEY,\n    user_id INT REFERENCES adr_users(user_id),\n    setting_key VARCHAR(100) NOT NULL,\n    setting_value VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP\n);\n\nCREATE TABLE adr_transaction_logs (\n    log_id SERIAL PRIMARY KEY,\n    transaction_id INT REFERENCES adr_transactions(transaction_id),\n    log_message TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n